import 'package:baseball_detector_flutter/data/models/ai_coach/action_plan.dart';
import 'package:baseball_detector_flutter/data/models/ai_coach/count_recommendations.dart';
import 'package:baseball_detector_flutter/data/models/ai_coach/lefty_strategy.dart';
import 'package:baseball_detector_flutter/data/models/ai_coach/new_pitch.dart';
import 'package:baseball_detector_flutter/data/models/ai_coach/pitch_features.dart';
import 'package:baseball_detector_flutter/data/models/ai_coach/pitch_zones.dart';
import 'package:baseball_detector_flutter/data/models/ai_coach/pros_cons.dart';
import 'package:baseball_detector_flutter/data/models/ai_coach/strikeout_strategy.dart';

part 'ai_coach_report_content.freezed.dart';
part 'ai_coach_report_content.g.dart';

@freezed
abstract class AICoachReportContent with _$AICoachReportContent {
  @JsonSerializable(
    explicitToJson: true,
    fieldRename: FieldRename.none,
  )
  const factory AICoachReportContent({
    @JsonKey(fromJson: _pitchFeaturesFromJson, toJson: _pitchFeaturesToJson)
    PitchFeatures? pitchFeatures,
    @JsonKey(fromJson: _prosConsFromJson, toJson: _prosConsToJson)
    ProsCons? prosCons,
    @JsonKey(fromJson: _countRecommendationsFromJson, toJson: _countRecommendationsToJson)
    List<CountRecommendationsEntry>? countRecommendations,
    @JsonKey(fromJson: _strikeoutStrategiesFromJson, toJson: _strikeoutStrategiesToJson)
    List<StrikeoutStrategy>? strikeoutStrategies,
    @JsonKey(fromJson: _leftyStrategiesFromJson, toJson: _leftyStrategiesToJson)
    List<LeftyStrategy>? leftyStrategies,
    @JsonKey(fromJson: _pitchZonesFromJson, toJson: _pitchZonesToJson)
    List<PitchZoneByPitch>? pitchZones,
    @JsonKey(fromJson: _newPitchesFromJson, toJson: _newPitchesToJson)
    List<Proposal>? newPitches,
    @JsonKey(fromJson: _actionPlansFromJson, toJson: _actionPlansToJson)
    List<ActionPlan>? actionPlans,
  }) = _AICoachReportContent;

  factory AICoachReportContent.fromJson(Map<String, dynamic> json) =>
      _$AICoachReportContentFromJson(json);
}

PitchFeatures? _pitchFeaturesFromJson(Map<String, dynamic>? json) {
  if (json == null || json.isEmpty) {
    return null;
  }
  try {
    return PitchFeatures.fromJson(json);
  } catch (error, stackTrace) {
    debugPrint('PitchFeatures.fromJson failed: $error\n$stackTrace');
    return null;
  }
}

Map<String, dynamic>? _pitchFeaturesToJson(PitchFeatures? value) {
  return value?.toJson();
}

ProsCons? _prosConsFromJson(Map<String, dynamic>? json) {
  if (json == null || json.isEmpty) {
    return null;
  }
  try {
    return ProsCons.fromJson(json);
  } catch (error, stackTrace) {
    debugPrint('ProsCons.fromJson failed: $error\n$stackTrace');
    return null;
  }
}

Map<String, dynamic>? _prosConsToJson(ProsCons? value) {
  return value?.toJson();
}

List<CountRecommendationsEntry>? _countRecommendationsFromJson(List<dynamic>? json) {
  if (json == null || json.isEmpty) {
    return null;
  }
  try {
    return json
        .map((e) => CountRecommendationsEntry.fromJson(e as Map<String, dynamic>))
        .toList();
  } catch (error, stackTrace) {
    debugPrint('CountRecommendationsEntry list parse failed: $error\n$stackTrace');
    return null;
  }
}

List<Map<String, dynamic>>? _countRecommendationsToJson(List<CountRecommendationsEntry>? value) {
  return value?.map((e) => e.toJson()).toList();
